import java.util.*;

public class Solution {
  public static long run(List<String> rows) {
    long hash = 1469598103934665603L;
    for (String row : rows) {
      int commaCount = 0;
      int b = 0;
      int c = 0;
      boolean hot = false;
      int len = row.length();
      int i = 0;

      // Skip first two columns
      while (i < len && commaCount < 2) {
        if (row.charAt(i) == ',') commaCount++;
        i++;
      }

      // Parse b (3rd column)
      while (i < len && row.charAt(i) != ',') {
        b = b * 10 + (row.charAt(i) - '0');
        i++;
      }
      commaCount++;
      i++;

      // Parse c (4th column)
      while (i < len && row.charAt(i) != ',') {
        c = c * 10 + (row.charAt(i) - '0');
        i++;
      }
      commaCount++;
      i++;

      // Check if 5th column is "hot"
      if (i < len && row.charAt(i) == 'h') {
        if (i + 2 < len && row.charAt(i + 1) == 'o' && row.charAt(i + 2) == 't') {
          hot = true;
        }
      }

      long v = (b > 300 ? (b + c) : 0) + (hot ? 29 : 0);
      hash ^= (v + 1);
      hash *= 1099511628211L;
    }
    return hash;
  }
}
